class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def plusOne(head: ListNode) -> ListNode:
    dummy = ListNode(0)
    dummy.next = head

    not_nine = dummy
    curr = head
    while curr:
        if curr.val != 9:
            not_nine = curr
        curr = curr.next

    not_nine.val += 1

    curr = not_nine.next
    while curr:
        curr.val = 0
        curr = curr.next

    if dummy.val == 1:
        return dummy
    else:
        return head
